/**
 * Centralized Pricing Configuration
 *
 * Update BASE_PRICE to automatically recalculate all pricing tiers
 */

// ============================================
// PRICING CONFIGURATION
// ============================================

/**
 * Base price for a single device license
 * Change this value to update all pricing tiers automatically
 */
export const BASE_PRICE = 29;

/**
 * Discount percentages for bulk purchases
 */
export const DISCOUNT_3_DEVICES = 0.10; // 10% off
export const DISCOUNT_5_DEVICES = 0.20; // 20% off

// ============================================
// CALCULATED PRICES
// ============================================

/**
 * Single device license price
 */
export const SINGLE_DEVICE_PRICE = BASE_PRICE;

/**
 * 3-device license price (10% discount)
 */
export const THREE_DEVICE_PRICE = parseFloat(((BASE_PRICE * 3) * (1 - DISCOUNT_3_DEVICES)).toFixed(2));

/**
 * 5-device license price (20% discount)
 */
export const FIVE_DEVICE_PRICE = parseFloat(((BASE_PRICE * 5) * (1 - DISCOUNT_5_DEVICES)).toFixed(2));

/**
 * Savings for 3-device license
 */
export const THREE_DEVICE_SAVINGS = parseFloat(((BASE_PRICE * 3) - THREE_DEVICE_PRICE).toFixed(2));

/**
 * Savings for 5-device license
 */
export const FIVE_DEVICE_SAVINGS = parseFloat(((BASE_PRICE * 5) - FIVE_DEVICE_PRICE).toFixed(2));

// ============================================
// PRICING TIERS
// ============================================

export interface PricingTier {
  devices: number;
  price: number;
  pricePerDevice: number;
  discount: number;
  savings: number;
  displayPrice: string;
  displaySavings: string;
}

export const PRICING_TIERS: PricingTier[] = [
  {
    devices: 1,
    price: SINGLE_DEVICE_PRICE,
    pricePerDevice: SINGLE_DEVICE_PRICE,
    discount: 0,
    savings: 0,
    displayPrice: `$${SINGLE_DEVICE_PRICE}`,
    displaySavings: '',
  },
  {
    devices: 3,
    price: THREE_DEVICE_PRICE,
    pricePerDevice: parseFloat((THREE_DEVICE_PRICE / 3).toFixed(2)),
    discount: DISCOUNT_3_DEVICES,
    savings: THREE_DEVICE_SAVINGS,
    displayPrice: `$${THREE_DEVICE_PRICE}`,
    displaySavings: `Save $${THREE_DEVICE_SAVINGS}`,
  },
  {
    devices: 5,
    price: FIVE_DEVICE_PRICE,
    pricePerDevice: parseFloat((FIVE_DEVICE_PRICE / 5).toFixed(2)),
    discount: DISCOUNT_5_DEVICES,
    savings: FIVE_DEVICE_SAVINGS,
    displayPrice: `$${FIVE_DEVICE_PRICE}`,
    displaySavings: `Save $${FIVE_DEVICE_SAVINGS}`,
  },
];

// ============================================
// HELPER FUNCTIONS
// ============================================

/**
 * Get pricing tier by device count
 */
export function getPricingTier(devices: number): PricingTier | undefined {
  return PRICING_TIERS.find(tier => tier.devices === devices);
}

/**
 * Calculate price for any number of devices with discount
 */
export function calculatePrice(devices: number): number {
  const tier = getPricingTier(devices);
  if (tier) {
    return tier.price;
  }

  // For custom device counts, use base price without discount
  return BASE_PRICE * devices;
}

/**
 * Format price for display
 */
export function formatPrice(price: number): string {
  return `$${price.toFixed(2)}`;
}

/**
 * Get discount percentage for device count
 */
export function getDiscountPercentage(devices: number): number {
  const tier = getPricingTier(devices);
  return tier ? tier.discount * 100 : 0;
}

// ============================================
// EXPORT ALL PRICING INFO
// ============================================

export const PRICING = {
  basePrice: BASE_PRICE,
  tiers: PRICING_TIERS,
  discounts: {
    threeDevices: DISCOUNT_3_DEVICES,
    fiveDevices: DISCOUNT_5_DEVICES,
  },
  prices: {
    single: SINGLE_DEVICE_PRICE,
    three: THREE_DEVICE_PRICE,
    five: FIVE_DEVICE_PRICE,
  },
  savings: {
    three: THREE_DEVICE_SAVINGS,
    five: FIVE_DEVICE_SAVINGS,
  },
  helpers: {
    getTier: getPricingTier,
    calculatePrice,
    formatPrice,
    getDiscountPercentage,
  },
} as const;

// ============================================
// PRICING SUMMARY (for logging/debugging)
// ============================================

export function printPricingSummary(): void {
  console.log('='.repeat(50));
  console.log('SERVERCOMPASS PRICING CONFIGURATION');
  console.log('='.repeat(50));
  console.log(`Base Price: $${BASE_PRICE}`);
  console.log('');
  PRICING_TIERS.forEach(tier => {
    console.log(`${tier.devices} Device${tier.devices > 1 ? 's' : ''}:`);
    console.log(`  Price: ${tier.displayPrice}`);
    console.log(`  Per Device: $${tier.pricePerDevice}`);
    if (tier.discount > 0) {
      console.log(`  Discount: ${(tier.discount * 100).toFixed(0)}% OFF`);
      console.log(`  Savings: $${tier.savings}`);
    }
    console.log('');
  });
  console.log('='.repeat(50));
}
